package runlengthencoding

// RunLengthEncoding encodes an array using run-length encoding.
func RunLengthEncoding(arr []int) []int {
	if len(arr) == 0 { return []int{} }
	result := []int{}
	count := 1
	for i := 1; i < len(arr); i++ {
		if arr[i] == arr[i-1] { count++ } else {
			result = append(result, arr[i-1], count)
			count = 1
		}
	}
	result = append(result, arr[len(arr)-1], count)
	return result
}

import java.util.*;

public class RunLengthEncoding {
    public static int[] runLengthEncoding(int[] arr) {
        if (arr.length == 0) return new int[0];
        List<Integer> result = new ArrayList<>();
        int count = 1;
        for (int i = 1; i < arr.length; i++) {
            if (arr[i] == arr[i - 1]) { count++; }
            else { result.add(arr[i - 1]); result.add(count); count = 1; }
        }
        result.add(arr[arr.length - 1]); result.add(count);
        return result.stream().mapToInt(Integer::intValue).toArray();
    }
}

fun runLengthEncoding(arr: IntArray): IntArray {
    if (arr.isEmpty()) return intArrayOf()
    val result = mutableListOf<Int>()
    var count = 1
    for (i in 1 until arr.size) {
        if (arr[i] == arr[i-1]) count++
        else { result.add(arr[i-1]); result.add(count); count = 1 }
    }
    result.add(arr.last()); result.add(count)
    return result.toIntArray()
}

def run_length_encoding(arr: list[int]) -> list[int]:
    if not arr:
        return []
    result = []
    count = 1
    for i in range(1, len(arr)):
        if arr[i] == arr[i - 1]:
            count += 1
        else:
            result.extend([arr[i - 1], count])
            count = 1
    result.extend([arr[-1], count])
    return result

pub fn run_length_encoding(arr: &[i32]) -> Vec<i32> {
    if arr.is_empty() { return vec![]; }
    let mut result = Vec::new();
    let mut count = 1;
    for i in 1..arr.len() {
        if arr[i] == arr[i-1] { count += 1; }
        else { result.push(arr[i-1]); result.push(count); count = 1; }
    }
    result.push(*arr.last().unwrap());
    result.push(count);
    result
}

object RunLengthEncoding {
  def runLengthEncoding(arr: Array[Int]): Array[Int] = {
    if (arr.isEmpty) return Array.empty[Int]
    val result = scala.collection.mutable.ArrayBuffer[Int]()
    var count = 1
    for (i <- 1 until arr.length) {
      if (arr(i) == arr(i-1)) count += 1
      else { result += arr(i-1); result += count; count = 1 }
    }
    result += arr.last; result += count
    result.toArray
  }
}

func runLengthEncoding(_ arr: [Int]) -> [Int] {
    if arr.isEmpty { return [] }
    var result: [Int] = []
    var count = 1
    for i in 1..<arr.count {
        if arr[i] == arr[i-1] { count += 1 }
        else { result.append(contentsOf: [arr[i-1], count]); count = 1 }
    }
    result.append(contentsOf: [arr.last!, count])
    return result
}

export function runLengthEncoding(arr: number[]): number[] {
    if (arr.length === 0) return [];
    const result: number[] = [];
    let count = 1;
    for (let i = 1; i < arr.length; i++) {
        if (arr[i] === arr[i - 1]) { count++; }
        else { result.push(arr[i - 1], count); count = 1; }
    }
    result.push(arr[arr.length - 1], count);
    return result;
}
